import type { ComponentProps, ComponentRef } from 'react';
import {
  Tour as TourPrimitive,
  useTour,
  useTourContext,
  waitForElement,
  waitForElementValue,
  waitForEvent,
  waitForPromise,
} from '@ark-ui/react/tour';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import styles from './Tour.module.css';

type TourRootProps = ComponentProps<typeof TourPrimitive.Root> & OverlayPortalProps;

function TourRoot({ portalled, portalRef, ...props }: TourRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <TourPrimitive.Root {...props} />
    </OverlayPortalProvider>
  );
}

const TourBackdrop = forwardRef<
  ComponentRef<typeof TourPrimitive.Backdrop>,
  ComponentProps<typeof TourPrimitive.Backdrop>
>(function TourBackdrop({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <TourPrimitive.Backdrop
        ref={ref}
        data-slot="tour-backdrop"
        className={clsx(styles.backdrop, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const TourSpotlight = forwardRef<
  ComponentRef<typeof TourPrimitive.Spotlight>,
  ComponentProps<typeof TourPrimitive.Spotlight>
>(function TourSpotlight({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <TourPrimitive.Spotlight
        ref={ref}
        data-slot="tour-spotlight"
        className={clsx(styles.spotlight, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const TourPositioner = forwardRef<
  ComponentRef<typeof TourPrimitive.Positioner>,
  ComponentProps<typeof TourPrimitive.Positioner>
>(function TourPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <TourPrimitive.Positioner
        ref={ref}
        data-slot="tour-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const TourContent = forwardRef<
  ComponentRef<typeof TourPrimitive.Content>,
  ComponentProps<typeof TourPrimitive.Content>
>(function TourContent({ className, ...props }, ref) {
  return (
    <TourPrimitive.Content
      ref={ref}
      data-slot="tour-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourArrow = forwardRef<
  ComponentRef<typeof TourPrimitive.Arrow>,
  ComponentProps<typeof TourPrimitive.Arrow>
>(function TourArrow({ className, children, ...props }, ref) {
  return (
    <TourPrimitive.Arrow
      ref={ref}
      data-slot="tour-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <TourArrowTip />}
    </TourPrimitive.Arrow>
  );
});

const TourArrowTip = forwardRef<
  ComponentRef<typeof TourPrimitive.ArrowTip>,
  ComponentProps<typeof TourPrimitive.ArrowTip>
>(function TourArrowTip({ className, ...props }, ref) {
  return (
    <TourPrimitive.ArrowTip
      ref={ref}
      data-slot="tour-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourTitle = forwardRef<
  ComponentRef<typeof TourPrimitive.Title>,
  ComponentProps<typeof TourPrimitive.Title>
>(function TourTitle({ className, ...props }, ref) {
  return (
    <TourPrimitive.Title
      ref={ref}
      data-slot="tour-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourDescription = forwardRef<
  ComponentRef<typeof TourPrimitive.Description>,
  ComponentProps<typeof TourPrimitive.Description>
>(function TourDescription({ className, ...props }, ref) {
  return (
    <TourPrimitive.Description
      ref={ref}
      data-slot="tour-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourProgressText = forwardRef<
  ComponentRef<typeof TourPrimitive.ProgressText>,
  ComponentProps<typeof TourPrimitive.ProgressText>
>(function TourProgressText({ className, ...props }, ref) {
  return (
    <TourPrimitive.ProgressText
      ref={ref}
      data-slot="tour-progress-text"
      className={clsx(styles.progressText, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourCloseTrigger = forwardRef<
  ComponentRef<typeof TourPrimitive.CloseTrigger>,
  ComponentProps<typeof TourPrimitive.CloseTrigger>
>(function TourCloseTrigger({ asChild, className, ...props }, ref) {
  return (
    <TourPrimitive.CloseTrigger
      ref={ref}
      asChild={asChild}
      data-slot="tour-close-trigger"
      className={clsx(!asChild && styles.closeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourControl = forwardRef<
  ComponentRef<typeof TourPrimitive.Control>,
  ComponentProps<typeof TourPrimitive.Control>
>(function TourControl({ className, ...props }, ref) {
  return (
    <TourPrimitive.Control
      ref={ref}
      data-slot="tour-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourActionTrigger = forwardRef<
  ComponentRef<typeof TourPrimitive.ActionTrigger>,
  ComponentProps<typeof TourPrimitive.ActionTrigger>
>(function TourActionTrigger({ asChild, className, ...props }, ref) {
  return (
    <TourPrimitive.ActionTrigger
      ref={ref}
      asChild={asChild}
      data-slot="tour-action-trigger"
      className={clsx(!asChild && styles.actionTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const TourActions = TourPrimitive.Actions;
const TourContext = TourPrimitive.Context;

const Tour = Object.assign(TourRoot, {
  Root: TourRoot,
  Backdrop: TourBackdrop,
  Spotlight: TourSpotlight,
  Positioner: TourPositioner,
  Content: TourContent,
  Arrow: TourArrow,
  ArrowTip: TourArrowTip,
  Title: TourTitle,
  Description: TourDescription,
  ProgressText: TourProgressText,
  CloseTrigger: TourCloseTrigger,
  Control: TourControl,
  Actions: TourActions,
  ActionTrigger: TourActionTrigger,
  Context: TourContext,
});

export {
  Tour,
  useTour,
  useTourContext,
  waitForElement,
  waitForElementValue,
  waitForEvent,
  waitForPromise,
};
export type { TourRootProps };
export type {
  TourActionTriggerProps,
  TourActionsProps,
  TourArrowProps,
  TourArrowTipProps,
  TourBackdropProps,
  TourCloseTriggerProps,
  TourContentProps,
  TourContextProps,
  TourControlProps,
  TourDescriptionProps,
  TourFocusOutsideEvent,
  TourInteractOutsideEvent,
  TourPointerDownOutsideEvent,
  TourPositionerProps,
  TourProgressTextProps,
  TourSpotlightProps,
  TourStepDetails,
  TourStepEffectArgs,
  TourTitleProps,
  UseTourContext,
  UseTourProps,
  UseTourReturn,
  WaitForEventOptions,
  WaitOptions,
} from '@ark-ui/react/tour';

@layer ui.components {
  .backdrop {
    z-index: calc(var(--tour-z-index, var(--z-modal)) + var(--layer-index, 0));
    background-color: var(--tour-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--tour-backdrop-blur, 4px)));

    &[data-state='open'] {
      animation: tour-backdrop-in var(--tour-backdrop-transition, var(--transition-default));
    }

    &[data-state='closed'] {
      animation: tour-backdrop-out var(--tour-backdrop-transition, var(--transition-default));
    }
  }

  .spotlight {
    z-index: calc(var(--tour-z-index, var(--z-modal)) + var(--tour-layer, 0));
    box-shadow: var(
      --tour-spotlight-shadow,
      0 0 0 var(--tour-spotlight-ring-width, 2px) var(--color-ring)
    );
  }

  .positioner {
    z-index: var(--z-index, var(--tour-z-index, var(--z-modal)));
    max-width: var(--available-width);
    max-height: var(--available-height);
    outline: 0;

    &[data-type='dialog'] {
      position: fixed;
      inset: 0;
      display: grid;
      place-items: center;
      overflow-y: auto;
      overscroll-behavior: contain;
      padding: var(--tour-positioner-padding, var(--spacing-4));
    }

    &[data-type='floating'] {
      position: fixed;
      z-index: var(--tour-z-index, var(--z-modal));
      margin: var(--tour-floating-offset, var(--spacing-6));

      &[data-placement*='top'] {
        inset-block-start: 0;
      }

      &[data-placement*='bottom'] {
        inset-block-end: 0;
      }

      &[data-placement*='start'] {
        inset-inline-start: 0;
      }

      &[data-placement*='end'] {
        inset-inline-end: 0;
      }
    }
  }

  .content {
    --arrow-background: var(--tour-arrow-background, var(--tour-bg, var(--color-popover)));
    --arrow-size: var(--tour-arrow-size, 0.625rem);

    box-sizing: border-box;
    position: relative;
    z-index: calc(var(--tour-z-index, var(--z-modal)) + var(--layer-index, 0));
    display: flex;
    flex-direction: column;
    gap: var(--tour-gap, var(--spacing-1));
    width: min(var(--tour-width, 20rem), var(--available-width, 100vw));
    max-width: min(
      var(--tour-max-width, calc(100vw - var(--spacing-8))),
      var(--available-width, 100vw)
    );
    max-height: min(var(--tour-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--tour-padding, var(--spacing-5));
    border: var(--tour-border-width, var(--border-width-sm)) solid
      var(--tour-border-color, var(--color-border));
    border-radius: var(--tour-radius, var(--radius-lg));
    background-color: var(--tour-bg, var(--color-popover));
    color: var(--tour-color, var(--color-popover-foreground));
    box-shadow: var(--tour-shadow, var(--shadow-lg));
    outline: 0;
    transform-origin: var(--transform-origin);

    &[data-state='open'] {
      animation: tour-content-in var(--tour-transition, var(--transition-default)) both;
    }

    &[data-state='closed'] {
      animation: tour-content-out var(--tour-transition, var(--transition-default)) both;
    }

    &[data-type='dialog'] {
      width: min(
        var(--tour-dialog-width, 26rem),
        var(--tour-max-width, calc(100vw - var(--spacing-8)))
      );
    }

    &[data-type='floating'] {
      width: min(
        var(--tour-floating-width, 22rem),
        var(--tour-max-width, calc(100vw - var(--spacing-8)))
      );
    }
  }

  .arrow {
    --arrow-background: var(--tour-arrow-background, var(--tour-bg, var(--color-popover)));
    --arrow-size: var(--tour-arrow-size, 0.625rem);
  }

  .arrowTip {
    border-top: var(--tour-border-width, var(--border-width-sm)) solid
      var(--tour-arrow-stroke-color, var(--tour-border-color, var(--color-border)));
    border-left: var(--tour-border-width, var(--border-width-sm)) solid
      var(--tour-arrow-stroke-color, var(--tour-border-color, var(--color-border)));
  }

  .title {
    margin: var(--tour-title-margin, 0);
    padding-inline-end: var(--tour-title-padding-inline-end, var(--spacing-6));
    color: var(--tour-title-color, var(--tour-color, var(--color-popover-foreground)));
    font-size: var(--tour-title-font-size, var(--text-md));
    font-weight: var(--tour-title-font-weight, var(--weight-semibold));
    line-height: var(--tour-title-line-height, var(--line-height-text-md));
  }

  .description {
    margin: var(--tour-description-margin, 0);
    color: var(--tour-description-color, var(--color-muted-foreground));
    font-size: var(--tour-description-font-size, var(--text-sm));
    line-height: var(--tour-description-line-height, var(--line-height-text-sm));
  }

  .progressText {
    order: 1;
    margin-top: var(--tour-progress-text-margin-top, var(--spacing-2));
    color: var(--tour-progress-text-color, var(--color-muted-foreground));
    font-size: var(--tour-progress-text-font-size, var(--text-xs));
    line-height: var(--tour-progress-text-line-height, var(--line-height-text-xs));
  }

  .closeTrigger {
    box-sizing: border-box;
    position: absolute;
    inset-block-start: var(--tour-close-trigger-offset, var(--spacing-2));
    inset-inline-end: var(--tour-close-trigger-offset, var(--spacing-2));
    display: inline-flex;
    width: var(--tour-close-trigger-size, 1.75rem);
    height: var(--tour-close-trigger-size, 1.75rem);
    align-items: center;
    justify-content: center;
    padding: 0;
    border: 0;
    border-radius: var(--tour-close-trigger-radius, var(--radius-md));
    background: var(--tour-close-trigger-bg, transparent);
    color: var(--tour-close-trigger-color, var(--color-muted-foreground));
    font: inherit;
    line-height: 1;
    cursor: pointer;

    :where(svg) {
      width: var(--tour-close-trigger-icon-size, 0.875rem);
      height: var(--tour-close-trigger-icon-size, 0.875rem);
    }

    @media (hover: hover) {
      &:hover {
        background: var(--tour-close-trigger-bg-hover, var(--color-accent));
        color: var(
          --tour-close-trigger-color-hover,
          var(--tour-color, var(--color-popover-foreground))
        );
      }
    }

    &:focus-visible {
      outline: var(--tour-focus-ring-width, var(--border-width-sm)) solid
        var(--tour-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--tour-focus-ring-width, var(--border-width-sm)) * -1);
    }
  }

  .control {
    order: 2;
    display: flex;
    justify-content: flex-end;
    flex-wrap: wrap;
    gap: var(--tour-control-gap, var(--spacing-2));
    margin-top: var(--tour-control-margin-top, var(--spacing-3));
  }

  .actionTrigger {
    box-sizing: border-box;
    display: inline-flex;
    min-height: var(--tour-action-height, 2rem);
    align-items: center;
    justify-content: center;
    gap: var(--tour-action-gap, var(--spacing-2));
    padding-block: var(--tour-action-padding-y, 0.375rem);
    padding-inline: var(--tour-action-padding-x, 0.75rem);
    border: var(--tour-action-border-width, var(--border-width-sm)) solid
      var(--tour-action-border-color, var(--color-border));
    border-radius: var(--tour-action-radius, var(--radius-md));
    background: var(--tour-action-bg, var(--color-background));
    color: var(--tour-action-color, var(--color-foreground));
    font: inherit;
    font-size: var(--tour-action-font-size, var(--text-sm));
    font-weight: var(--tour-action-font-weight, var(--weight-medium));
    line-height: var(--tour-action-line-height, var(--line-height-text-sm));
    text-decoration: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color var(--tour-action-transition, var(--transition-default)),
      border-color var(--tour-action-transition, var(--transition-default)),
      color var(--tour-action-transition, var(--transition-default));

    &[data-type='next'],
    &[data-type='close'] {
      border-color: var(--tour-action-primary-border-color, var(--color-primary));
      background: var(--tour-action-primary-bg, var(--color-primary));
      color: var(--tour-action-primary-color, var(--color-primary-foreground));
    }

    @media (hover: hover) {
      &:hover:not([data-disabled], :disabled) {
        background: var(--tour-action-bg-hover, var(--color-accent));
      }

      &:is([data-type='next'], [data-type='close']):hover:not([data-disabled], :disabled) {
        border-color: var(
          --tour-action-primary-border-color-hover,
          color-mix(in oklab, var(--color-primary), black 12%)
        );
        background: var(
          --tour-action-primary-bg-hover,
          color-mix(in oklab, var(--color-primary), black 12%)
        );
      }
    }

    &:focus-visible {
      outline: var(--tour-focus-ring-width, var(--border-width-sm)) solid
        var(--tour-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--tour-focus-ring-width, var(--border-width-sm)) * -1);
    }

    &[data-disabled],
    &:disabled {
      pointer-events: none;
      opacity: var(--tour-disabled-opacity, var(--opacity-disabled));
    }
  }

  @keyframes tour-backdrop-in {
    from {
      opacity: var(--tour-backdrop-starting-opacity, 0);
      backdrop-filter: var(--tour-backdrop-starting-blur, none);
    }
  }

  @keyframes tour-backdrop-out {
    to {
      opacity: var(--tour-backdrop-ending-opacity, 0);
      backdrop-filter: var(--tour-backdrop-ending-blur, none);
    }
  }

  @keyframes tour-content-in {
    from {
      opacity: var(--tour-content-starting-opacity, 0);
      translate: var(--tour-content-starting-translate-x, 0)
        var(--tour-content-starting-translate-y, 0);
      scale: var(--tour-content-starting-scale, var(--scale-popup));
    }
  }

  @keyframes tour-content-out {
    to {
      opacity: var(--tour-content-ending-opacity, 0);
      translate: var(--tour-content-ending-translate-x, 0) var(--tour-content-ending-translate-y, 0);
      scale: var(--tour-content-ending-scale, var(--scale-popup));
    }
  }
}
